1124 static VPIRValue *tryToFoldLiveIns(VPSingleDefRecipe &R,
1125                                    ArrayRef<VPValue *> Operands,
1126                                    const DataLayout &DL,
1127                                    VPTypeAnalysis &TypeInfo) {
