5519 void VPlanTransforms::updateScalarResumePhis(
5520     VPlan &Plan, DenseMap<VPValue *, VPValue *> &IVEndValues, bool FoldTail) {
5521   VPTypeAnalysis TypeInfo(Plan);
5522   auto *ScalarPH = Plan.getScalarPreheader();
5523   auto *MiddleVPBB = cast<VPBasicBlock>(ScalarPH->getPredecessors()[0]);
5524   VPRegionBlock *VectorRegion = Plan.getVectorLoopRegion();
5525   VPBuilder VectorPHBuilder(
5526       cast<VPBasicBlock>(VectorRegion->getSinglePredecessor()));
5527   VPBuilder MiddleBuilder(MiddleVPBB, MiddleVPBB->getFirstNonPhi());
5528   for (VPRecipeBase &PhiR : Plan.getScalarPreheader()->phis()) {
5529     auto *ResumePhiR = cast<VPPhi>(&PhiR);
5530 
5531     // TODO: Extract final value from induction recipe initially, optimize to
5532     // pre-computed end value together in optimizeInductionExitUsers.
5533     auto *VectorPhiR = cast<VPHeaderPHIRecipe>(ResumePhiR->getOperand(0));
5534     if (auto *WideIVR = dyn_cast<VPWidenInductionRecipe>(VectorPhiR)) {
5535       // TODO: Check if tail is folded directly in VPlan.
5536       VPValue *TC = !FoldTail
5537                         ? static_cast<VPValue *>(&Plan.getVectorTripCount())
5538                         : Plan.getTripCount();
5539       if (VPValue *EndValue = tryToComputeEndValueForInduction(
5540               WideIVR, VectorPHBuilder, TypeInfo, TC)) {
5541         IVEndValues[WideIVR] = EndValue;
5542         ResumePhiR->setOperand(0, EndValue);
5543         ResumePhiR->setName("bc.resume.val");
5544         continue;
5545       }
5546       // TODO: Also handle truncated inductions here. Computing end-values
5547       // separately should be done as VPlan-to-VPlan optimization, after
5548       // legalizing all resume values to use the last lane from the loop.
5549       assert(cast<VPWidenIntOrFpInductionRecipe>(VectorPhiR)->getTruncInst() &&
5550              "should only skip truncated wide inductions");
5551       continue;
5552     }
5553 
5554     // The backedge value provides the value to resume coming out of a loop,
5555     // which for FORs is a vector whose last element needs to be extracted. The
5556     // start value provides the value if the loop is bypassed.
5557     bool IsFOR = isa<VPFirstOrderRecurrencePHIRecipe>(VectorPhiR);
5558     auto *ResumeFromVectorLoop = VectorPhiR->getBackedgeValue();
5559     assert(VectorRegion->getSingleSuccessor() == Plan.getMiddleBlock() &&
5560            "Cannot handle loops with uncountable early exits");
5561     if (IsFOR) {
5562       auto *ExtractPart = MiddleBuilder.createNaryOp(
5563           VPInstruction::ExtractLastPart, ResumeFromVectorLoop);
5564       ResumeFromVectorLoop = MiddleBuilder.createNaryOp(
5565           VPInstruction::ExtractLastLane, ExtractPart, DebugLoc::getUnknown(),
5566           "vector.recur.extract");
5567     }
5568     ResumePhiR->setName(IsFOR ? "scalar.recur.init" : "bc.merge.rdx");
5569     ResumePhiR->setOperand(0, ResumeFromVectorLoop);
5570   }
