1051           Escape = optimizeEarlyExitInductionUser(
1052               Plan, TypeInfo, PredVPBB, ExitIRI->getOperand(Idx), PSE);
1053         if (Escape)
1054           ExitIRI->setOperand(Idx, Escape);
1055       }
1056     }
1057   }
