1673 void VPIRPhi::execute(VPTransformState &State) {
1674   PHINode *Phi = &getIRPhi();
1675   for (const auto &[Idx, Op] : enumerate(operands())) {
1676     VPValue *ExitValue = Op;
1677     auto Lane = vputils::isSingleScalar(ExitValue)
1678                     ? VPLane::getFirstLane()
1679                     : VPLane::getLastLaneForVF(State.VF);
1680     VPBlockBase *Pred = getParent()->getPredecessors()[Idx];
1681     auto *PredVPBB = Pred->getExitingBasicBlock();
1682     BasicBlock *PredBB = State.CFG.VPBB2IRBB[PredVPBB];
1683     // Set insertion point in PredBB in case an extract needs to be generated.
1684     // TODO: Model extracts explicitly.
1685     State.Builder.SetInsertPoint(PredBB->getTerminator());
1686     Value *V = State.get(ExitValue, VPLane(Lane));
1687     // If there is no existing block for PredBB in the phi, add a new incoming
1688     // value. Otherwise update the existing incoming value for PredBB.
1689     if (Phi->getBasicBlockIndex(PredBB) == -1)
1690       Phi->addIncoming(V, PredBB);
1691     else
1692       Phi->setIncomingValueForBlock(PredBB, V);
1693   }
1694 
1695   // Advance the insert point after the wrapped IR instruction. This allows
1696   // interleaving VPIRInstructions and other recipes.
1697   State.Builder.SetInsertPoint(Phi->getParent(), std::next(Phi->getIterator()));
1698 }
